li.OKResult:

local nR = me:RandomInt(1, 10) 
if nR <= 4 then
	me:AddMsg(XT("[NAME]以真气炼化晶洞。虽已尽力掌控，最终也只化出一批玉精。"));
	me:DropAwardItemFromCache(story.ItemCache2, 1, 1);
elseif nR > 4 and nR <= 6  then
	me:AddMsg(XT("[NAME]以真气炼化晶洞。对其中躁动灵机掌控颇佳，晶洞化作一批玉精，并显出更稀有之物！"));
	me:DropAwardItemFromCache(story.ItemCache2, 1, 1);
	me:DropAwardItemFromCache(story.ItemCache3, 1, 1);
	me:DropAwardItem("Item_SpiritJadeEmbryo", 1);		
elseif nR <= 7 then
	me:AddMsg(XT("[NAME]以真气炼化晶洞。对其中躁动灵机掌控极佳，竟炼出两件地脉珍宝。"));
	me:DropAwardItemFromCache(story.ItemCache3, 1, 1);
	me:DropAwardItemFromCache(story.ItemCache3, 1, 1);
	me:DropAwardItem("Item_SpiritJadeEmbryo", 1);	
else
	me:AddMsg("[NAME] 炼化d the Geode but the thread of Qi, while their control was good it seems the jade was lacking something and the Qi at its core simply became a piece of Jade Essence");	
    me:DropAwardItem("Item_JadeEssence", 1);
end
story:RemoveBindItem();


me:AddMsg(XT("[NAME]端详星核灵胚时，隐隐感到自身灵机与之呼应。"));
me:AddModifier("HotStory_MedicineLv");
me:AddModifier("HotStory_MiningLv");
me:AddModifier("HotStory_ManualLv");
me:SetFlag(701, 1);


local nR = me:RandomInt(1, 6) 
if nR == 1 then
	me:AddMsg(XT("[NAME]随手破开聚合物，一缕闪光黏液渗出。收集之时，总令人有些毛骨悚然。"));
	me:DropAwardItem("Item_SoulCrystalYou", 1);
elseif nR == 2 then
	me:AddMsg(XT("[NAME]果断破开聚合物，一枚温润雅致的碎片映入眼帘，其中灵光令人心神安定。"));
	me:DropAwardItem("Item_SoulCrystalNing", 1);	
elseif nR == 3 then
	me:AddMsg(XT("[NAME]小心剖开聚合物，一枚璀璨而坚实的晶体跃入眼中，竟忍不住朗声一笑。"));
	me:DropAwardItem("Item_SoulCrystalLing", 1);
else
	me:AddMsg("[NAME] Broke open the Agglomeration but it was just reflected light.");	
end
story:RemoveBindItem();


